const body = $json.body || $json;
const brands = (body.brands || []).map(b => String(b).trim()).filter(Boolean);
const run_id = 'run_' + Date.now().toString(36) + Math.random().toString(36).slice(2, 8);
const run_date = new Date().toISOString().split('T')[0];
if (brands.length === 0) return [{ json: { run_id, brand: '', run_date, status: 'error' } }];
return brands.map(brand => ({ json: { run_id, brand, run_date, status: 'queued' } }));

const items = $('Init Run').all().map(i => i.json);
const run_id = items[0] ? items[0].run_id : '';
const brands = items.map(i => i.brand).filter(Boolean);
const force = (($('Webhook').first().json.body || {}).force) === true;
return [{ json: { run_id, brands, force } }];

const reqRun = String((($('Webhook1').first().json.query)||{}).run_id || '');
const rows = $input.all().map(i => i.json).filter(r => r && String(r.run_id) === reqRun);
const total = rows.length;
const done = rows.filter(r => String(r.status).toLowerCase() === 'done').length;
const errored = rows.filter(r => String(r.status).toLowerCase() === 'error').length;
function parse(r){ try { return r.dashboard_json ? JSON.parse(r.dashboard_json) : null; } catch(e){ return null; } }
return [{ json: {
  run_id: reqRun,
  finished: total > 0 && (done + errored) >= total,
  total, done, errored,
  brands: rows.map(r => ({
    brand: r.brand,
    status: String(r.status || 'queued').toLowerCase(),
    dashboard: String(r.status).toLowerCase() === 'done' ? parse(r) : null
  }))
} }];

const trig = $('Execute Workflow Trigger').first().json || {};
const requested = (trig.brands || []).map(b => String(b).trim().toLowerCase());
if (requested.length === 0) return $input.all();
return $input.all().filter(it =>
  requested.includes(String(it.json['Brand Name'] || '').trim().toLowerCase())
);

// Sanitize handles so the scrapers get the format each API expects.
// Tolerates leading @, stray spaces, and full URLs pasted into the sheet.
function bare(v){
  return String(v || '')
    .trim()
    .replace(/^@+/, '')          // drop leading @
    .replace(/\s+/g, '');        // drop internal/trailing spaces
}
function slug(v){
  // LinkedIn company slug: strip URL if pasted, lowercase, spaces -> hyphen
  let s = String(v || '').trim();
  const m = s.match(/linkedin\.com\/company\/([^\/?#]+)/i);
  if (m) s = m[1];
  return s.toLowerCase().replace(/\s+/g, '-').replace(/^@+/, '');
}
return $input.all().map(it => {
  const r = it.json;
  return { json: {
    ...r,
    'Brand Name':       (r['Brand Name'] || '').trim(),
    'LinkedIn_Handle':  slug(r['LinkedIn_Handle']),
    'Instagram_Handle': bare(r['Instagram_Handle']),
    'YouTube_Handle':   bare(r['YouTube_Handle']),
    'Facebook_Handle':  bare(r['Facebook_Handle']),
    'Twitter_Handle':   bare(r['Twitter_Handle'])
  }};
});

const brand = $('Loop Each Brand').item.json['Brand Name'] || '';
const handle = $('Loop Each Brand').item.json['LinkedIn_Handle'] || '';
const data = $input.first().json;
const posts = Array.isArray(data.posts) ? data.posts : [];
if (posts.length === 0) return [{ json: { _source: 'linkedin', _brand: brand, _handle: handle, _empty: true } }];
return posts.map(p => ({ json: { ...p, _source: 'linkedin', _brand: brand, _handle: handle } }));

const brand = $('Loop Each Brand').item.json['Brand Name'] || '';
const handle = $('Loop Each Brand').item.json['Instagram_Handle'] || '';
const data = $input.first().json;
let posts = [];
if (Array.isArray(data.posts)) posts = data.posts;
else if (data.data?.user?.edge_owner_to_timeline_media?.edges) posts = data.data.user.edge_owner_to_timeline_media.edges.map(e => e.node);
else if (Array.isArray(data.data)) posts = data.data;
else if (Array.isArray(data.items)) posts = data.items;
if (posts.length === 0) return [{ json: { _source: 'instagram', _brand: brand, _handle: handle, _empty: true } }];
return posts.map(p => {
  let captionText = '';
  if (typeof p.caption === 'string') captionText = p.caption;
  else if (p.caption && typeof p.caption === 'object') captionText = p.caption.text || '';
  else if (p.edge_media_to_caption?.edges?.[0]?.node?.text) captionText = p.edge_media_to_caption.edges[0].node.text;
  const likes = p.like_count ?? p.likes ?? p.likeCount ?? p.edge_liked_by?.count ?? 0;
  const comments = p.comment_count ?? p.comments ?? p.commentCount ?? p.edge_media_to_comment?.count ?? 0;
  let timestamp = '';
  if (p.taken_at) timestamp = new Date(p.taken_at * 1000).toISOString();
  else if (p.taken_at_timestamp) timestamp = new Date(p.taken_at_timestamp * 1000).toISOString();
  else if (p.timestamp) timestamp = p.timestamp;
  const thumb = p.display_url || p.thumbnail_url || p.image_versions2?.candidates?.[0]?.url || (p.image_versions?.items?.[0]?.url) || '';
  return { json: { ...p, _caption: captionText, _likes: likes, _comments: comments, _timestamp: timestamp, _thumb: thumb, _source: 'instagram', _brand: brand, _handle: handle } };
});

const brand = $('Loop Each Brand').item.json['Brand Name'] || '';
const handle = $('Loop Each Brand').item.json['YouTube_Handle'] || '';
const data = $input.first().json;
let posts = [];
if (Array.isArray(data.videos)) posts = data.videos;
else if (Array.isArray(data.data)) posts = data.data;
else if (Array.isArray(data.items)) posts = data.items;
else if (data && typeof data === 'object') posts = [data];
if (posts.length === 0) return [{ json: { _source: 'youtube', _brand: brand, _handle: handle, _empty: true } }];
return posts.map(p => {
  const thumb = p.thumbnail || p.thumbnails?.high?.url || p.thumbnails?.[0]?.url || '';
  const views = p.viewCount ?? p.views ?? p.view_count ?? p.statistics?.viewCount ?? 0;
  const likes = p.likeCount ?? p.likes ?? p.statistics?.likeCount ?? 0;
  const comments = p.commentCount ?? p.comments ?? p.statistics?.commentCount ?? 0;
  let timestamp = p.publishedAt || p.publishTime || p.uploadDate || '';
  return { json: { ...p, _likes: likes, _comments: comments, _views: views, _thumb: thumb, _timestamp: timestamp, _source: 'youtube', _brand: brand, _handle: handle } };
});

const brand = $('Loop Each Brand').item.json['Brand Name'] || '';
const handle = $('Loop Each Brand').item.json['Facebook_Handle'] || '';
const data = $input.first().json;
let posts = [];
if (Array.isArray(data.posts)) posts = data.posts;
else if (Array.isArray(data.data)) posts = data.data;
else if (Array.isArray(data.items)) posts = data.items;
if (posts.length === 0) return [{ json: { _source: 'facebook', _brand: brand, _handle: handle, _empty: true } }];
return posts.map(p => ({
  json: {
    ...p,
    _likes: p.reactionCount ?? p.like_count ?? 0,
    _comments: p.commentCount ?? p.comment_count ?? 0,
    _shares: p.shareCount ?? p.share_count ?? 0,
    _views: p.videoViewCount ?? p.view_count ?? 0,
    _thumb: p.imageUrl || p.thumbnailUrl || p.image || '',
    _timestamp: p.publishTime ? new Date(p.publishTime * 1000).toISOString() : (p.timestamp || ''),
    _source: 'facebook', _brand: brand, _handle: handle
  }
}));

const brand = $('Loop Each Brand').item.json['Brand Name'] || '';
const handle = $('Loop Each Brand').item.json['Twitter_Handle'] || '';
const data = $input.first().json;
let posts = [];
if (Array.isArray(data.tweets)) posts = data.tweets;
else if (Array.isArray(data.data)) posts = data.data;
else if (Array.isArray(data.items)) posts = data.items;
if (posts.length === 0) return [{ json: { _source: 'twitter', _brand: brand, _handle: handle, _empty: true } }];
return posts.map(p => ({
  json: {
    ...p,
    _likes: p.favorite_count ?? 0,
    _comments: p.reply_count ?? 0,
    _shares: p.retweet_count ?? 0,
    _views: Number(p.view_count ?? 0),
    _timestamp: p.created_at ? new Date(p.created_at).toISOString() : '',
    _url: p.id ? `https://twitter.com/i/web/status/${p.id}` : (p.url || ''),
    _text: p.full_text || p.text || '',
    _thumb: p.media?.[0]?.media_url_https || p.entities?.media?.[0]?.media_url_https || '',
    _source: 'twitter', _brand: brand, _handle: handle
  }
}));

const items = $input.all();
const normalized = [];

// Deterministic estimate factors (no AI, no randomness)
// reach ~ engagement * REACH_FACTOR, impressions ~ reach * IMPR_FACTOR
const REACH_FACTOR = { instagram: 90, linkedin: 60, facebook: 70, youtube: 1.2, twitter: 110 };
const IMPR_FACTOR = 1.5;

function fmtK(n){ n=Number(n)||0; if(n>=1e6) return (n/1e6).toFixed(1)+'M'; if(n>=1e3) return (n/1e3).toFixed(1)+'K'; return String(n); }

for (const item of items) {
  const p = item.json;
  if (!p || p._empty) continue;
  const source = p._source || 'unknown';
  const brand  = p._brand  || '';
  const handle = p._handle || '';

  let post_url = p._url || '';
  if (!post_url) {
    if (p.shortcode) post_url = `https://www.instagram.com/p/${p.shortcode}/`;
    else post_url = p.url || p.postUrl || p.link || p.permalinkUrl || p.videoUrl || String(p.id || '');
  }

  const post_text = p._text || p._caption || p.text ||
    (typeof p.caption === 'string' ? p.caption : '') ||
    p.edge_media_to_caption?.edges?.[0]?.node?.text ||
    p.description || p.title || p.content || p.full_text || '';

  const likes = Number(p._likes ?? p.likes ?? p.likesCount ?? p.likeCount ?? p.edge_liked_by?.count ?? p.numLikes ?? p.favoriteCount ?? p.favorite_count ?? 0) || 0;
  const comments = Number(p._comments ?? p.comments ?? p.commentsCount ?? p.commentCount ?? p.edge_media_to_comment?.count ?? p.numComments ?? p.replyCount ?? p.reply_count ?? 0) || 0;
  const shares = Number(p._shares ?? p.shares ?? p.sharesCount ?? p.shareCount ?? p.retweetCount ?? p.retweet_count ?? p.repostCount ?? 0) || 0;
  const views = Number(p._views ?? p.views ?? p.viewCount ?? p.viewsCount ?? p.video_view_count ?? p.playCount ?? p.videoViewCount ?? p.view_count ?? 0) || 0;
  const thumb = p._thumb || p.display_url || p.thumbnail || p.imageUrl || '';

  let timestamp = p._timestamp || '';
  if (!timestamp) timestamp = p.timestamp || p.datePublished || p.date || p.publishedAt || p.createdAt || p.time || p.created_at || '';
  if (!timestamp && p.taken_at) timestamp = new Date(p.taken_at * 1000).toISOString();
  else if (!timestamp && p.taken_at_timestamp) timestamp = new Date(p.taken_at_timestamp * 1000).toISOString();

  // Derived metrics
  const engagement = likes + comments + shares;
  const rf = REACH_FACTOR[source] || 80;
  const reach = source === 'youtube'
      ? Math.round(views * rf)            // youtube: reach derived from views
      : Math.round(engagement * rf + likes * 5);
  const impressions = Math.round(reach * IMPR_FACTOR);
  const denom = reach > 0 ? reach : (engagement > 0 ? engagement * 50 : 1);
  const engRate = Math.min(100, Number(((engagement / denom) * 100).toFixed(1)));

  // Format date as "DD Mon YYYY"
  let displayDate = '';
  if (timestamp) {
    const dt = new Date(timestamp);
    if (!isNaN(dt)) displayDate = dt.toLocaleDateString('en-GB', { day:'2-digit', month:'short', year:'numeric' });
  }

  normalized.push({
    json: {
      brand,
      handle,
      plateform: source,
      post_url: String(post_url).substring(0, 500),
      post_text: String(post_text).substring(0, 800),
      likes, comments, shares, views,
      engagement,
      eng_rate: engRate,
      est_reach: fmtK(reach),
      est_impressions: fmtK(impressions),
      thumb: String(thumb).substring(0, 500),
      display_date: displayDate,
      timestamps: String(timestamp),
      run_date: new Date().toISOString().split('T')[0]
    }
  });
}

if (normalized.length === 0) {
  return [{ json: { brand:'no_data', handle:'', plateform:'none', post_url:'', post_text:'', likes:0, comments:0, shares:0, views:0, engagement:0, eng_rate:0, est_reach:'0', est_impressions:'0', thumb:'', display_date:'', timestamps:'', run_date:new Date().toISOString().split('T')[0] } }];
}
return normalized;

// Build a single rich prompt for NVIDIA NIM that returns EVERY dashboard block.
const posts = $input.first().json.all_posts || [];
const brandName = $('Loop Each Brand').first().json['Brand Name'] || '';

// Trim posts to keep the prompt within context limits
const trimmed = posts
  .filter(p => p.brand !== 'no_data')
  .slice(0, 25)
  .map((p, i) => ({
    id: i,
    platform: p.plateform,
    text: (p.post_text || '').substring(0, 240),
    likes: p.likes, comments: p.comments, shares: p.shares, views: p.views
  }));

const schema = `Return ONLY valid raw JSON (no markdown, no backticks, no commentary) with EXACTLY this shape:
{
  "sentiment_score": <number 0-100>,
  "summary": "<max 220 chars market overview>",
  "post_sentiments": [ { "id": <int>, "sentiment": "positive|negative|neutral", "intent": "Appreciation|Product Inquiry|General Discussion|Complaint|Feedback|Suggestion|Brand Promo|Support Request" } ],
  "keywords": [ { "name": "<context>", "count": <int>, "nss": <number -10..10> } ],
  "intents": [ { "name": "<intent>", "total": <int>, "pos": <int>, "neg": <int>, "neu": <int> } ],
  "cross_brands": [ { "name": "<brand>", "weight": <int 1-100> } ],
  "handles": [ { "name": "<@handle>", "weight": <int 1-100> } ],
  "products": [ { "name": "<product>", "weight": <int 1-100> } ],
  "product_sentiment": [ { "name": "<product>", "pos": <int 0-100>, "neg": <int 0-100> } ],
  "locations": [ { "name": "<place>", "pos": <int>, "neg": <int>, "neu": <int> } ]
}
Rules:
- post_sentiments MUST contain one entry per input post id.
- keywords: 8-13 items, the key contexts/themes across posts.
- intents: cover all 8 intent categories listed; set counts to 0 if absent.
- cross_brands/handles/products: extract real entities mentioned; weight = relative frequency.
- product_sentiment: pos+neg should sum to 100 per product.
- locations: places mentioned or implied (default India-centric if unclear).`;

const promptText =
  `You are a social-media analytics engine. Analyze these posts for the brand "${brandName}".\n` +
  schema + `\nPosts JSON: ` + JSON.stringify(trimmed);

return [{ json: { promptText, brandName, postCount: trimmed.length } }];

